const { BigQuery } = require('@google-cloud/bigquery');
const bigquery = new BigQuery();

exports.processLargeDataset = async (req, res) => {
  // Set timeout and memory limits
  const timeout = 540000; // 540 seconds
  const maxMemory = 8 * 1024 * 1024 * 1024; // 8GB
  
  // Validate input
  if (!req.body.query) {
    return res.status(400).json({ error: 'Query parameter is required' });
  }
  
  try {
    // Execute BigQuery job with proper error handling
    const queryJob = bigquery.createQueryJob({
      query: req.body.query,
      useQueryCache: true,
      useLegacySql: false,
    });
    
    const [job] = await queryJob;
    
    // Monitor job progress
    const [results] = await job.getQueryResults();
    
    // Process results in chunks to prevent memory issues
    const chunkSize = 1000;
    const processedResults = [];
    
    for (let i = 0; i < results.length; i += chunkSize) {
      const chunk = results.slice(i, i + chunkSize);
      // Process chunk here
      const processedChunk = chunk.map(row => {
        // Sanitize and process each row
        const sanitizedRow = {};
        Object.keys(row).forEach(key => {
          sanitizedRow[key] = sanitizeInput(row[key]);
        });
        return sanitizedRow;
      });
      
      processedResults.push(...processedChunk);
      
      // Clear memory periodically
      if (i % (chunkSize * 10) === 0) {
        await new Promise(resolve => setImmediate(resolve));
      }
    }
    
    res.status(200).json({
      success: true,
      count: processedResults.length,
      data: processedResults
    });
    
  } catch (error) {
    console.error('Error processing dataset:', error);
    res.status(500).json({ 
      error: 'Failed to process dataset',
      details: error.message 
    });
  }
};

// Sanitize input to prevent injection attacks
function sanitizeInput(input) {
  if (typeof input === 'string') {
    // Remove potentially dangerous characters
    return input
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
      .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');
  }
  return input;
}

